import enum

class ResolvedWriteUpLinkType(enum.Enum):
  """Indicates what kind of content a resolved WriteUpLink points to"""
  RESOLVED_WRITE_UP_LINK_TYPE_UNSPECIFIED = 0
  RESOLVED_WRITE_UP_LINK_TYPE_DATASET = 1
  RESOLVED_WRITE_UP_LINK_TYPE_NOTEBOOK = 2
  RESOLVED_WRITE_UP_LINK_TYPE_MODEL = 3
  RESOLVED_WRITE_UP_LINK_TYPE_BENCHMARK = 4
  RESOLVED_WRITE_UP_LINK_TYPE_YOUTUBE = 5
  RESOLVED_WRITE_UP_LINK_TYPE_EXTERNAL = 6
  RESOLVED_WRITE_UP_LINK_TYPE_IMAGE = 7

class WriteUpLinkLocation(enum.Enum):
  WRITE_UP_LINK_LOCATION_UNSPECIFIED = 0
  ADDITIONAL_LINKS = 1
  CAROUSEL = 2

class WriteUpLinkMediaType(enum.Enum):
  WRITE_UP_LINK_MEDIA_TYPE_UNSPECIFIED = 0
  IMAGE = 1
  VIDEO = 2

class WriteUpType(enum.Enum):
  WRITE_UP_TYPE_UNSPECIFIED = 0
  HACKATHON_PROJECT = 1
  COMPETITION_SOLUTION = 2
  PERSONAL_PROJECT = 3
  KNOWLEDGE = 4
  FORUM_TOPIC = 5
  BLOG = 6

